"""
This module defines the Game class to manage the checkers game.
"""

class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = 'red'

    def switch_turn(self):
        if self.current_player == 'red':
            self.current_player = 'black'
        else:
            self.current_player = 'red'

    def make_move(self, start, end):
        return self.board.move(start, end, self.current_player)

    def check_winner(self):
        winner = self.board.check_winner()
        if winner:
            print(f"{winner} wins!")
            return True
        if self.board.no_moves_left():
            print("Draw!")
            return True
        return False

    def play_game(self):
        while not self.check_winner():
            start, end = input(f"Player {self.current_player}, enter your move (e.g., e2-e4): ").split('-')
            result = self.make_move(start, end)
            if result:
                print("Invalid move. Please try again.")
                continue
            self.switch_turn()

if __name__ == "__main__":
    game = Game()
    game.play_game()
```

