"""
This module defines the Board class to manage the checkers board.
"""

class Board:
    def __init__(self):
        self.board = self.initialize_board()

    def initialize_board(self):
        # Initialize an 8x8 board with alternating red and black pieces
        board = [[' ' for _ in range(8)] for _ in range(8)]
        for i in range(3):
            for j in range((i + 1) % 2, 8, 2):
                board[i][j] = 'r'
                board[7 - i][7 - j] = 'b'
        return board

    def print_board(self):
        for row in self.board:
            print(" ".join(row))

    def move(self, start, end, player):
        # Check if the move is valid
        if not (0 <= int(start[0]) < 8 and 0 <= int(end[0]) < 8 and 0 <= int(start[1]) < 8 and 0 <= int(end[1]) < 8):
            return True

        start_row, start_col = int(start[0]), int(start[1])
        end_row, end_col = int(end[0]), int(end[1])

        if self.board[start_row][start_col] != player or (self.board[end_row][end_col] != ' ' and self.board[end_row][end_col] != 'K'):
            return True

        # Check if the move is a capture
        row_diff, col_diff = abs(end_row - start_row), abs(end_col - start_col)

        if row_diff == 2 and col_diff == 2:
            mid_row, mid_col = (start_row + end_row) // 2, (start_col + end_col) // 2
            if self.board[mid_row][mid_col] == (player if player == 'r' else 'B') or (self.board[mid_row][mid_col] == 'R' and player == 'b') or (self.board[mid_row][mid_col] == 'B' and player == 'r'):
                self.board[start_row][start_col], self.board[end_row][end_col] = ' ', self.board[mid_row][mid_col]
                self.board[mid_row][mid_col] = ' '
                return False

        # Check if the move is a simple jump
        if row_diff == 1 and col_diff == 1:
            self.board[start_row][start_col], self.board[end_row][end_col] = ' ', player
            return False

        return True

    def check_winner(self):
        red_pieces = sum(row.count('r') for row in self.board)
        black_pieces = sum(row.count('b') for row in self.board)

        if red_pieces == 0:
            return 'black'
        elif black_pieces == 0:
            return 'red'
        else:
            return None

    def no_moves_left(self):
        # Check if there are any valid moves left for the current player
        pass
